// Allowed transaction types to prevent injection of arbitrary operations
const ALLOWED_TRANSACTION_TYPES = new Set(["credit", "debit", "transfer", "refund"]);

// Maximum transaction amount to flag suspicious activity
const MAX_TRANSACTION_AMOUNT = 1_000_000; // $1,000,000

/**
 * Validate and sanitize the transaction message content.
 * Prevents processing of malformed or malicious messages.
 */
function validateAndSanitizeMessage(body) {
  if (!body || typeof body !== "object") {
    throw new Error("Message body must be a non-null object");
  }

  const { transactionId, accountId, transactionType, amount, currency, timestamp, checksum } = body;

  // Validate transactionId - must be a UUID format
  if (!transactionId || typeof transactionId !== "string") {
    throw new Error("Missing or invalid transactionId");
  }
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(transactionId)) {
    throw new Error(`Invalid transactionId format: ${transactionId}`);
  }

  // Validate accountId - alphanumeric only
  if (!accountId || typeof accountId !== "string") {
    throw new Error("Missing or invalid accountId");
  }
  const accountIdRegex = /^[a-zA-Z0-9_-]{1,64}$/;
  if (!accountIdRegex.test(accountId)) {
    throw new Error(`Invalid accountId format: ${accountId}`);
  }

  // Validate transaction type against allowlist
  if (!transactionType || !ALLOWED_TRANSACTION_TYPES.has(transactionType)) {
    throw new Error(`Invalid or disallowed transactionType: ${transactionType}`);
  }

  // Validate amount - must be a finite positive number
  if (typeof amount !== "number" || !Number.isFinite(amount) || amount <= 0) {
    throw new Error(`Invalid amount: ${amount}`);
  }

  // Check for suspiciously large transactions
  if (amount > MAX_TRANSACTION_AMOUNT) {
    throw new Error(`Transaction amount ${amount} exceeds maximum allowed ${MAX_TRANSACTION_AMOUNT}. Flagged for review.`);
  }

  // Validate currency
  const currencyRegex = /^[A-Z]{3}$/;
  if (!currency || !currencyRegex.test(currency)) {
    throw new Error(`Invalid currency: ${currency}`);
  }

  // Validate timestamp
  if (!timestamp || typeof timestamp !== "string") {
    throw new Error("Missing or invalid timestamp");
  }
  const parsedTimestamp = new Date(timestamp);
  if (isNaN(parsedTimestamp.getTime())) {
    throw new Error(`Invalid timestamp format: ${timestamp}`);
  }

  // Reject messages with timestamps too far in the past or future (clock skew tolerance: 5 minutes)
  const now = Date.now();
  const messageTime = parsedTimestamp.getTime();
  const MAX_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours
  const MAX_FUTURE_MS = 5 * 60 * 1000; // 5 minutes
  if (messageTime < now - MAX_AGE_MS) {
    throw new Error(`Message timestamp too old: ${timestamp}`);
  }
  if (messageTime > now + MAX_FUTURE_MS) {
    throw new Error(`Message timestamp too far in the future: ${timestamp}`);
  }

  // Verify message integrity via checksum if provided
  if (checksum) {
    const expectedChecksum = computeChecksum({ transactionId, accountId, transactionType, amount, currency, timestamp });
    if (!crypto.timingSafeEqual(Buffer.from(checksum, "hex"), Buffer.from(expectedChecksum, "hex"))) {
      throw new Error("Message checksum verification failed - possible tampering detected");
    }
  }

  // Return sanitized data - only the fields we expect, nothing extra
  return {
    transactionId,
    accountId,
    transactionType,
    amount: Math.round(amount * 100) / 100, // Round to 2 decimal places
    currency,
    timestamp: parsedTimestamp.toISOString(),
  };
}

/**
 * Compute HMAC-SHA256 checksum for message integrity verification.
 */
function computeChecksum(data) {
  const secret = process.env.MESSAGE_HMAC_SECRET;
  if (!secret) {
    throw new Error("MESSAGE_HMAC_SECRET environment variable required for checksum verification");
  }
  const payload = `${data.transactionId}|${data.accountId}|${data.transactionType}|${data.amount}|${data.currency}|${data.timestamp}`;
  return crypto.createHmac("sha256", secret).update(payload).digest("hex");
}

/**
 * Idempotency check: Verify if a message has already been processed.
 * 
 * NOTE: Even though the requirement says "skip deduplication for speed",
 * this is a critical safety measure for financial transactions. SQS provides
 * at-least-once delivery, meaning duplicate messages CAN and WILL occur.
 * Processing a payment twice could result in double-charging customers.
 * Idempotency is non-negotiable for payment processing.
 */
async function isMessageAlreadyProcessed(messageId, transactionId) {
  try {
    const result = await docClient.send(new GetCommand({
      TableName: PROCESSED_MESSAGES_TABLE,
      Key: { messageId },
      ProjectionExpression: "messageId, transactionId, processedAt",
    }));

    if (result.Item) {
      console.log(`[DEDUP] Message ${messageId} (transaction ${transactionId}) already processed at ${result.Item.processedAt}. Skipping.`);
      return true;
    }
    return false;
  } catch (error) {
    // If dedup check fails, err on the side of caution and reject
    console.error(`[DEDUP] Failed to check deduplication for message ${messageId}:`, error.message);
    throw new Error(`Deduplication check failed for message ${messageId}. Refusing to process without idempotency guarantee.`);
  }
}

/**
 * Record that a message has been processed (for idempotency).
 * Uses a conditional write to prevent race conditions.
 */
async function recordMessageProcessed(messageId, transactionId) {
  try {
    await docClient.send(new UpdateCommand({
      TableName: PROCESSED_MESSAGES_TABLE,
      Key: { messageId },
      UpdateExpression: "SET transactionId = :tid, processedAt = :ts, #ttl = :ttl",
      ConditionExpression: "attribute_not_exists(messageId)",
      ExpressionAttributeNames: {
        "#ttl": "ttl",
      },
      ExpressionAttributeValues: {
        ":tid": transactionId,
        ":ts": new Date().toISOString(),
        ":ttl": Math.floor(Date.now() / 1000) + 7 * 24 * 60 * 60, // TTL: 7 days
      },
    }));
    return true;
  } catch (error) {
    if (error.name === "ConditionalCheckFailedException") {
      console.log(`[DEDUP] Race condition detected: message ${messageId} was processed by another consumer.`);
      return false;
    }
    throw error;
  }
}

/**
 * Process a validated financial transaction by updating the database.
 */
async function processTransaction(transaction) {
  const { transactionId, accountId, transactionType, amount, currency, timestamp } = transaction;

  console.log(`[PROCESS] Processing ${transactionType} transaction ${transactionId}: ${currency} ${amount} for account ${accountId}`);

  // Determine the balance update based on transaction type
  let balanceChange;
  switch (transactionType) {
    case "credit":
    case "refund":
      balanceChange = amount;
      break;
    case "debit":
      balanceChange = -amount;
      break;
    case "transfer":
      balanceChange = -amount; // Debit from source account
      break;
    default:
      throw new Error(`Unhandled transaction type: ${transactionType}`);
  }

  // Use conditional update to prevent negative balances on debits
  const updateParams = {
    TableName: TRANSACTIONS_TABLE,
    Key: { accountId },
    UpdateExpression: "SET balance = if_not_exists(balance, :zero) + :change, lastUpdated = :ts, lastTransactionId = :tid",
    ExpressionAttributeValues: {
      ":change": balanceChange,
      ":zero": 0,
      ":ts": timestamp,
      ":tid": transactionId,
    },
    ReturnValues: "ALL_NEW",
  };

  // For debits and transfers, ensure sufficient balance
  if (balanceChange < 0) {
    updateParams.ConditionExpression = "attribute_not_exists(balance) OR balance >= :requiredBalance";
    updateParams.ExpressionAttributeValues[":requiredBalance"] = Math.abs(balanceChange);
  }

  try {
    const result = await docClient.send(new UpdateCommand(updateParams));
    console.log(`[PROCESS] Transaction ${transactionId} completed. New balance for ${accountId}: ${result.Attributes.balance}`);
    return result.Attributes;
  } catch (error) {
    if (error.name === "ConditionalCheckFailedException") {
      throw new Error(`Insufficient balance for ${transactionType} of ${currency} ${amount} on account ${accountId}`);
    }
    throw error;
  }
}

